// ** Material UI Imports
import { Stack } from "@mui/material";

// ** Styled Components
import { HatomButton, StyledText } from "./styledComponents";

/**
 * @desc Buy Tokens section (Top of Features Section)
 * @example
 * <BuyTokens />
 * @return {ReactElement}
 */
const BuyTokens = () => {
  return (
    <Stack
      mt={"2rem"}
      width={{ xs: "50%", md: "52rem" }}
      direction={{ xs: "column", md: "row" }}
      justifyContent={"space-between"}
      alignItems="center"
      spacing={{ xs: 4, md: 0 }}
    >
      <Stack direction={"column"}>
        <Stack direction={"row"} spacing={1}>
          <StyledText fontSize={{ xs: "1.6rem", md: "2.2rem" }}>
            $9,449,627.26
          </StyledText>
          <StyledText
            fontSize={{ xs: "1.6rem", md: "2.2rem" }}
            color={"#179C64"}
          >
            Dividends
          </StyledText>
        </Stack>
        <StyledText
          fontSize={{ xs: ".9rem", md: "1.15rem" }}
          textAlign={"left"}
          color={"#5c5c5c"}
          variant={"span"}
        >
          Paid out to Hatom Token Holders over 3 years
        </StyledText>
      </Stack>
      <HatomButton variant="contained">Buy Hatom Token</HatomButton>
    </Stack>
  );
};

export default BuyTokens;

// ** Material UI Imports
import { Stack, Typography } from "@mui/material";

// ** Styled Components
import { StyledText } from "./styledComponents";

/**
 * @desc Feature component for Features Section
 * @example
 * <Feature title={""}>...</Feature>
 * @param {object} props - React Properties
 * @param {string} props.title - title for the feature
 * @param {ReactElement} props.children - inner text as react children
 * @return {ReactElement}
 */
const Feature = ({ title, children }) => {
  return (
    <Stack
      alignItems={{ xs: "center", md: "flex-start" }}
      width={{ xs: "15rem", lg: "20rem" }}
      spacing={3}
    >
      <StyledText fontSize={{ xs: "2rem", md: "1.8rem", lg: "2.2rem" }}>
        {title}
      </StyledText>
      <Typography
        textAlign={{ xs: "center", md: "left" }}
        variant="span"
        fontSize={{ xs: ".8rem", lg: "1rem" }}
        color={"#5c5c5c"}
        fontFamily={"Neue Haas Grotesk Text Pro"}
        letterSpacing={".12rem"}
      >
        {children}
      </Typography>
    </Stack>
  );
};

export default Feature;

// ** Material UI Imports
import { Stack } from "@mui/material";

// ** User Components
import BuyTokens from "./BuyTokens";
import FeaturesList from "./FeaturesList";
import FeaturesTitle from "./FeaturesTitle";

// ** Styled Components
import { FeaturesWrapper } from "./styledComponents";

/**
 * @desc Features Section React Component
 * @example
 * <Features />
 * @return {ReactElement}
 */
const Features = () => {
  return (
    <FeaturesWrapper
      id="Features"
      width={"100vw"}
      alignItems={"center"}
      spacing={6}
      direction={{ xs: "column-reverse", md: "column" }}
    >
      <BuyTokens />
      <Stack
        pt={{ xs: "22rem", md: 0 }}
        width={"100vw"}
        spacing={6}
        alignItems={"center"}
      >
        <FeaturesTitle />
        <FeaturesList />
      </Stack>
    </FeaturesWrapper>
  );
};

export default Features;

// ** Material UI Imports
import { Stack } from "@mui/material";

// ** User Components
import Feature from "./Feature";

// ** Styled Components
import { FeatureListWrapper } from "./styledComponents";

/**
 * @desc List of all instances of Feature Component
 * @example
 * <FeaturesList />
 * @return {ReactElement}
 */
const FeaturesList = () => {
  return (
    <FeatureListWrapper
      width={{ xs: "95%", lg: "77rem" }}
      direction={{ xs: "column", md: "row" }}
      justifyContent={"space-between"}
      alignItems={{ xs: "center", md: "normal" }}
      spacing={{ xs: 7, md: 0 }}
    >
      <Stack spacing={{ xs: 7, md: 10 }}>
        <Feature title={"Earn"}>
          Lorem ipsum dolor sit amet consectetur adipisicing elit. Vel minus
          nam, temporibus, laborum odit iusto consectetur nesciunt obcaecati
        </Feature>
        <Feature title={"Borrow"}>
          Lorem ipsum dolor sit amet consectetur adipisicing elit. Vel minus
          nam, temporibus, laborum odit iusto consectetur nesciunt obcaecati
        </Feature>
      </Stack>
      <Feature title={"Dividends"}>
        Lorem ipsum dolor sit amet consectetur adipisicing elit. Vel minus nam,
        temporibus, laborum odit iusto consectetur nesciunt obcaecati
      </Feature>
    </FeatureListWrapper>
  );
};

export default FeaturesList;

// ** Styled Components
import { StyledText } from "./styledComponents";

/**
 * @desc Title of the Features Section
 * @example
 * <FeaturesTitle />
 * @return {ReactElement}
 */
const FeaturesTitle = () => {
  return (
    <StyledText
      pt={"3rem"}
      width={{ xs: "40%", md: "95%", lg: "77rem" }}
      textAlign={{ xs: "center", md: "left" }}
      fontSize={{ xs: "1.8rem", md: "2.5rem" }}
    >
      <span style={{ color: "#3555f7" }}>Features </span>
      of Hatom Protocol
    </StyledText>
  );
};

export default FeaturesTitle;

// ** Material UI Imports
import { Stack } from "@mui/material";

// ** Styled Components
import { StyledText } from "./styledComponents";

/**
 * @desc List for the Footer Section
 * @example
 * <FooterList title={""}>...</FooterList>
 * @param {object} props - React Properties
 * @param {string} props.title - title for the footer List
 * @param {ReactElement} props.children - inner list Components as react children
 * @return {ReactElement}
 */
const FooterList = ({ title, children }) => {
  return (
    <Stack
      direction={"column"}
      alignItems={"flex-start"}
      spacing={5}
      pl={"2rem"}
      py={{ xs: "2rem", md: 0 }}
      width={{ xs: "45vw", md: "unset" }}
    >
      <StyledText color={"#ffffff"} fontSize={"1.2rem"}>
        {title}
      </StyledText>
      {children}
    </Stack>
  );
};

export default FooterList;

// ** Material UI Imports
import { Stack } from "@mui/material";

// ** Styled Components
import {
  AppButtonBorder,
  AppButtonContained,
  FooterListItem,
  FooterLogo,
  FooterWrapper,
} from "./styledComponents";

// ** User Components
import FooterList from "./FooterList";

// ** Footer Logo
import Logo from "../media/logo-footer.png";

// ** React Width Hook
import { useWindowWidth } from "@react-hook/window-size";

/**
 * @desc Footer Section React Component
 * @example
 * <HatomFooter />
 * @return {ReactElement}
 */
const HatomFooter = () => {
  const width = useWindowWidth();
  return (
    <FooterWrapper direction={"row"}>
      <Stack width={{ xs: "100vw", md: "unset" }}>
        <FooterLogo src={Logo} />
      </Stack>
      <FooterList title={"Protocol"}>
        <FooterListItem>Markets</FooterListItem>
        <FooterListItem>Prices</FooterListItem>
        <FooterListItem>Docs</FooterListItem>
      </FooterList>
      <FooterList title={"Governance"}>
        <FooterListItem>Overview</FooterListItem>
        <FooterListItem>Hatom Token</FooterListItem>
      </FooterList>
      <FooterList title={"Security"}>
        <FooterListItem>Audits</FooterListItem>
        <FooterListItem>Formal Verification</FooterListItem>
        <FooterListItem>Economy Security</FooterListItem>
        <FooterListItem>Bug Bounty</FooterListItem>
      </FooterList>
      {width > 900 && (
        <AppButtonBorder>
          <AppButtonContained>App</AppButtonContained>
        </AppButtonBorder>
      )}
    </FooterWrapper>
  );
};

export default HatomFooter;

// ** Material UI Imports
import { Stack } from "@mui/material";
import MenuIcon from "@mui/icons-material/Menu";

// ** Styled Components
import {
  AppButtonBorder,
  AppButtonContained,
  HeaderLogo,
  HeaderText,
} from "./styledComponents";

// ** React Width Hook
import { useWindowWidth } from "@react-hook/window-size";

// ** Header Logo
import Logo from "../media/logo.svg";

/**
 * @desc Header Section React Component
 * @example
 * <HatomHeader/>
 * @return {ReactElement}
 */
const HatomHeader = () => {
  const width = useWindowWidth();
  return (
    <Stack
      position={"absolute"}
      top={0}
      zIndex={100}
      width={{ xs: "90vw", md: "70vw" }}
      height={{ xs: "5rem", md: "7rem" }}
      direction={"row"}
      justifyContent={"space-between"}
      alignItems="center"
      color={"white"}
    >
      <Stack>
        <HeaderLogo src={Logo} />
      </Stack>
      {width > 900 && (
        <Stack direction={"row"} spacing={2}>
          <HeaderText>Market</HeaderText>
          <HeaderText>Governance</HeaderText>
          <HeaderText>Prices</HeaderText>
          <HeaderText>Docs</HeaderText>
          <HeaderText
            color={"#3555F7 !important"}
            borderBottom={"1px solid #3555F7"}
          >
            Hatom Token
          </HeaderText>
        </Stack>
      )}
      <Stack
        direction={"row"}
        spacing={2}
        alignItems={"center"}
        fontSize={"2rem"}
      >
        <AppButtonBorder variant="contained">
          <AppButtonContained>App</AppButtonContained>
        </AppButtonBorder>
        {width < 900 && <MenuIcon color="inherit" fontSize="inherit" />}
      </Stack>
    </Stack>
  );
};

export default HatomHeader;

// ** Material UI Imports
import { Stack } from "@mui/material";

// ** Styled Components
import { StyledText } from "./styledComponents";

/**
 * @desc page Title React Component
 * @example
 * <HatomTitle />
 * @return {ReactElement}
 */
const HatomTitle = () => {
  return (
    <Stack position="absolute" top={"10rem"} zIndex={10}>
      <Stack maxHeight={"7rem"}>
        <StyledText color={"#3D906A"} fontSize={"5rem"}>
          Hatom Token
        </StyledText>
        <StyledText
          sx={{
            transform: "translate(-4px,-7.5rem)",
            filter: "drop-shadow(21px -6px 18px #7B7B7B)",
          }}
          color={"white"}
          fontSize={"5rem"}
        >
          Hatom Token
        </StyledText>
      </Stack>
      <StyledText
        color={"#3D906A"}
        fontSize={"1.2rem"}
        fontWeight={"normal !important"}
      >
        Lorem ipsum dolor sit amet consectetur adipisicing elit
      </StyledText>
    </Stack>
  );
};

export default HatomTitle;

// ** Styled Components
import { LabSectionStyled, Background, OverLay } from "./styledComponents";

/**
 * @desc LabSection Container React Component
 * @example
 * <LabSection>...</LabSection>
 * @param {object} props - React Properties
 * @param {ReactElement} props.children - inner components as react children
 * @return {ReactElement}
 */
const LabSection = ({ children }) => {
  return (
    <LabSectionStyled>
      <Background></Background>
      <OverLay></OverLay>
      {children}
    </LabSectionStyled>
  );
};

export default LabSection;

// ** Material UI Imports
import { Stack } from "@mui/material";

// ** Styled Components
import {
  HatomButton,
  InputWrapper,
  NewsInput,
  NewsWrapper,
  StyledText,
} from "./styledComponents";

// ** React width Hook
import { useWindowWidth } from "@react-hook/window-size";

/**
 * @desc Newsletter Section React Component
 * @example
 * <NewsLetter />
 * @return {ReactElement}
 */
const NewsLetter = () => {
  const width = useWindowWidth();
  return (
    <NewsWrapper spacing={4}>
      <Stack>
        <StyledText color={"#ffffff"} fontSize={"3rem"}>
          Subscribe to Hatom newsletter
        </StyledText>
        <StyledText
          color={"#C4D3EA"}
          fontSize={"1.5rem"}
          fontWeight={"normal !important"}
        >
          Lorem ipsum dolor sit amet, consectetur adipisicing elit.
        </StyledText>
      </Stack>
      <InputWrapper
        direction={"row"}
        width={{ xs: "25rem", md: "40rem" }}
        alignSelf={"center"}
      >
        <NewsInput placeholder="Enter your Email" disableUnderline />
        {width > 900 && <HatomButton>Subscribe</HatomButton>}
      </InputWrapper>
      {width < 900 && (
        <Stack width={"10rem"} alignSelf="center">
          <HatomButton>Subscribe</HatomButton>
        </Stack>
      )}
    </NewsWrapper>
  );
};

export default NewsLetter;

// ** Material UI Imports
import { styled } from "@mui/system";
import { Button, Input, Stack, Typography } from "@mui/material";

// ** Media Imports
import bg from "../media/bg.svg";
import bgMobile from "../media/bg-mobile.png";
import overlight from "../media/over-light.svg";
import coinsequence from "../media/coin-sequence.png";
import linesLarge from "../media/lines-large.svg";
import linesMedium from "../media/lines-medium.svg";
import linesMobile from "../media/lines-mobile.svg";

/**
 * @desc Background for Lab Section
 * @example
 * <Background></Background>
 */
export const Background = styled("div")({
  backgroundImage: `url(${bg})`,
  backgroundPosition: "center",
  backgroundRepeat: "no-repeat",
  backgroundSize: "cover",
  width: "100vw",
  height: "90rem",
  position: "absolute",
  top: 0,
  "@media screen and (max-width:900px)": {
    height: "80rem",
    backgroundImage: `url(${bgMobile})`,
  },
});

/**
 * @desc Lab Section Wrapper Styles
 * @example
 * <LabSectionStyled>...</LabSectionStyled>
 */
export const LabSectionStyled = styled("div")({
  width: "100vw",
  height: "90rem",
  display: "flex",
  justifyContent: "center",
  alignItems: "center",
  "@media screen and (max-width:900px)": {
    height: "80rem",
  },
});

/**
 * @desc Lab Section Tube Overlay
 * @example
 * <OverLay></OverLay>
 */
export const OverLay = styled("div")({
  width: "100vw",
  height: "90rem",
  backgroundImage: `url(${overlight})`,
  backgroundPosition: "center",
  backgroundRepeat: "no-repeat",
  backgroundSize: "cover",
  position: "absolute",
  top: 0,
  zIndex: 5,
  "@media screen and (max-width:900px)": {
    height: "80rem",
    backgroundImage: "none",
  },
});

/**
 * @desc Coin Styles
 * @example
 * <Coin></Coin>
 */
export const Coin = styled("div")({
  transform: "translate(2.5vw, 50px) scale(0.65)",
  width: "400px",
  height: "400px",
  backgroundImage: `url(${coinsequence})`,
  backgroundRepeat: "no-repeat",
  "@media screen and (max-width:1200px)": {
    transform: "translate(2.5vw, 50px) scale(0.55)",
  },
  "@media screen and (max-width:900px)": {
    transform: "translate(2.5vw, 70px) scale(0.45)",
  },
});

/**
 * @desc Custom button for the main page
 * @example
 * <HatomButton variant="contained">...</HatomButton>
 */
export const HatomButton = styled(Button)({
  borderRadius: "7px",
  textTransform: "none",
  fontFamily: "Neue Haas Grotesk Text Pro",
  fontSize: "1.1rem",
  color: "#ffffff",
  background: "rgb(27,67,71)", // eslint-disable-next-line
  background:
    "linear-gradient(270deg, rgba(27,67,71,1) 0%, rgba(61,144,106,1) 100%)",
  height: "3.5rem",
});

/**
 * @desc Features Section Wrapper
 * @example
 * <FeaturesWrapper direction="column">...</FeaturesWrapper>
 */
export const FeaturesWrapper = styled(Stack)({
  "@media screen and (max-width: 900px)": {
    backgroundImage: `url(${linesMobile})`,
    backgroundRepeat: "no-repeat",
    backgroundSize: "auto auto",
    backgroundPosition: "center 18rem",
  },
});

/**
 * @desc Features List Wrapper
 * @example
 * <FeaturesListWrapper direction="row">...</FeaturesListWrapper>
 */
export const FeatureListWrapper = styled(Stack)({
  backgroundImage: `url(${linesLarge})`,
  backgroundRepeat: "no-repeat",
  backgroundSize: "auto auto",
  backgroundPosition: "11rem 1.2rem",
  "@media screen and (max-width: 1200px)": {
    backgroundSize: "36rem auto",
    backgroundPosition: "14vw 2rem",
  },
  "@media screen and (max-width: 1150px)": {
    backgroundImage: `url(${linesMedium})`,
    backgroundSize: "28rem auto",
    backgroundPosition: "17vw 2rem",
  },
  "@media screen and (max-width: 900px)": {
    backgroundImage: "none",
  },
});

/**
 * @desc Styled Text Component
 * @example
 * <StyledText color="" variant="" fontSize=""></StyledText>
 */
export const StyledText = styled(Typography)({
  fontFamily: "Neue Haas Grotesk Text Pro",
  fontWeight: "bold",
});

/**
 * @desc Header Text Component
 * @example
 * <HeaderText variant="" fontSize=""></HeaderText>
 */
export const HeaderText = styled(Typography)({
  fontFamily: "Neue Haas Grotesk Text Pro",
  fontSize: "1rem",
  fontWeight: "bold",
  color: "#ffffff",
});

/**
 * @desc Header Logo Styled
 * @example
 * <HeaderLogo src={""}/>
 */
export const HeaderLogo = styled("img")({
  maxHeight: "10rem",
});

/**
 * @desc App Button Gradient Border
 * @example
 * <AppButtonBorder>...</AppButtonBorder>
 */
export const AppButtonBorder = styled("div")({
  borderRadius: "7px",
  maxWidth: "fit-content",
  maxHeight: "3rem",
  display: "flex",
  justifyContent: "center",
  alignItems: "center",
  padding: "1px",
  background:
    "linear-gradient(90deg, rgba(53,85,247,1) 0%, rgba(0,77,0,1) 52%, rgba(0,77,0,1) 100%)",
});

/**
 * @desc App Button
 * @example
 * <AppButton>...</AppButton>
 */
export const AppButtonContained = styled(Button)({
  fontFamily: "Neue Haas Grotesk Text Pro",
  fontWeight: "bold",
  width: "5rem",
  height: "3rem",
  textTransform: "none",
  color: "white",
  borderRadius: "7px",
  background: "rgb(0,77,0)", // eslint-disable-next-line
  background: "linear-gradient(90deg, rgba(0,77,0,1) 0%, rgba(1,48,30,1) 100%)",
});

// ** Newsletter Wrapper
/**
 * @desc Newsletter Wrapper
 * @example
 * <NewsWrapper direction="column">...</NewsWrapper>
 */
export const NewsWrapper = styled(Stack)({
  background: "rgb(38,91,92)", //eslint-disable-next-line
  background:
    "linear-gradient(90deg, rgba(38,91,92,1) 0%, rgba(17,86,107,1) 100%)",
  width: "100vw",
  minHeight: "10rem",
  marginTop: "3rem",
  padding: "5rem 0",
});

/**
 * @desc Newsletter Input Wrapper
 * @example
 * <InputWrapper direction="row">...</InputWrapper>
 */
export const InputWrapper = styled(Stack)({
  padding: "10px",
  direction: "row",
  borderRadius: "10px",
  alignItems: "center",
  justifyContent: "space-between",
  background: "#315B82",
});

/**
 * @desc Styled Input for Newsletter
 * @example
 * <NewsWrapper disableUnderline value="" onChange=""/>
 */
export const NewsInput = styled(Input)({
  fontSize: "1.3rem",
  padding: "0 1rem",
  color: "white",
});

/**
 * @desc Footer Wrapper
 * @example
 * <FooterWrapper direction="row">...</FooterWrapper>
 */
export const FooterWrapper = styled(Stack)({
  padding: "10rem 0",
  background: "#031222",
  width: "100vw",
  minHeight: "10rem",
  justifyContent: "space-around",
  flexWrap: "wrap",
  "@media screen and (max-width: 900px)": {
    justifyContent: "normal",
  },
});

/**
 * @desc Footer Logo Styled
 * @example
 * <HeaderLogo src={""}/>
 */
export const FooterLogo = styled("img")({
  width: "4rem",
  height: "4rem",
  "@media screen and (max-width: 900px)": {
    padding: "2rem",
  },
});

// ** Footer List Item
/**
 * @desc Footer List item
 * @example
 * <FooterListItem></FooterListItem>
 */
export const FooterListItem = styled(Typography)({
  fontFamily: "Neue Haas Grotesk Text Pro",
  fontSize: "1rem",
  fontWeight: "normal",
  color: "#6A7DAA",
});
